import React, { useState } from 'react';
// import './styles/claude-theme.css'; // Remove CSS import

import FileUpload from './components/FileUpload';



const annex3Questions = [
    {
        question: 'Is Background (existing knowledge) of TNO required to achieve the TNO Results or do you (basically) start from scratch? If yes, please describe/specify the Background.',
        answer: ''
    },
    {
        question: 'Does TNO have the required access rights to the needed Background? In other words: is TNO not limited to use and give access rights to its Background due to other contractual obligations (e.g. licenses)?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background to be able to use their Results after the Project?',
        answer: ''
    },
    {
        question: 'Does TNO need access rights to Background or Results of partners for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'What will be the Results (in terms of IPR/Foreground) for TNO?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to the TNO Results to be able to use their Results of the project after the Project?',
        answer: ''
    },
    {
        question: 'Will TNO realize the Results on its own or will other Partners also create and own part of these Results (resulting in Joint IP)? Please specify.',
        answer: ''
    },
    {
        question: 'Will the TNO Results be able to operate on itself after the project or is access to Background or Results of other Partners necessary to be able to use these Results?',
        answer: ''
    },
];

const App: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    // In a real app, answers would be set after processing the file
    const [answers, setAnswers] = useState(annex3Questions);
    const [openIndexes, setOpenIndexes] = useState<number[]>([]);

    const toggleOpen = (idx: number) => {
        setOpenIndexes((prev) =>
            prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
        );
    };

    const handleFileSelected = (file: File) => {
        setSelectedFile(file);
        // setAnswers([]); // Reset or trigger processing here
    };

    return (
        <div className="min-h-screen bg-neutral-950 flex flex-col items-center justify-center px-4 py-8">
            <main className="w-full max-w-2xl">
                {/* Header */}
                <div className="flex flex-col items-center mb-12">
                    <img src="/logo192.png" alt="EPIFs Assistant Logo" className="w-12 h-12 mb-4" />
                    <h1 className="text-lg font-medium text-slate-300 tracking-wide uppercase">EPIFs Assistant</h1>
                    <p className="text-sm text-slate-500 mt-2">Upload your document and get instant answers to your questionnaire.</p>
                </div>

                {/* Upload Section */}
                <div className="w-full bg-white dark:bg-neutral-900 rounded-xl shadow-lg border border-slate-200 p-8 flex flex-col items-center mb-8">
                    <FileUpload onFileSelected={handleFileSelected} selectedFile={selectedFile} setSelectedFile={setSelectedFile} />
                    {selectedFile && (
                        <button
                            className="mt-8 w-full py-3 px-4 rounded-lg bg-accent hover:bg-accent-dark text-white font-medium text-base transition-colors focus-visible:ring-2 focus-visible:ring-accent focus-visible:outline-none disabled:opacity-60 disabled:cursor-not-allowed"
                            disabled={false}
                        >
                            Analyse
                        </button>
                    )}
                </div>

                {/* Response Area */}
                {selectedFile && (
                    <div className="w-full animate-fade-in">
                        <h2 className="text-xs font-medium tracking-wide uppercase text-slate-400 mb-6">Annex 3 Questions</h2>
                        <div className="flex flex-col gap-3">
                            {answers.map((item, idx) => {
                                const isOpen = openIndexes.includes(idx);
                                return (
                                    <div
                                        key={idx}
                                        className="border border-slate-200 bg-slate-50 dark:bg-neutral-800 dark:border-neutral-700 rounded-lg p-4 cursor-pointer transition-shadow hover:shadow-md focus-visible:ring-2 focus-visible:ring-accent focus-visible:outline-none"
                                        onClick={() => toggleOpen(idx)}
                                        tabIndex={0}
                                        onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && toggleOpen(idx)}
                                        role="button"
                                        aria-expanded={isOpen}
                                    >
                                        <div className="flex items-start justify-between gap-3">
                                            <span className="text-sm font-medium text-slate-700 dark:text-slate-300 flex-1">{item.question}</span>
                                            <span className="text-accent text-lg flex-shrink-0">{isOpen ? '▲' : '▼'}</span>
                                        </div>
                                        {isOpen && (
                                            <div className="mt-3 pt-3 border-t border-slate-200 dark:border-neutral-700 text-sm text-slate-700 dark:text-slate-300 transition-opacity duration-200">
                                                {selectedFile ? item.answer || <span className="text-slate-400">(No answer extracted)</span> : <span className="text-slate-400">(Answer will appear here)</span>}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}
            </main>

            {/* Footer */}
            <footer className="w-full text-center py-4 text-slate-500 text-xs mt-12">
                © {new Date().getFullYear()} EPIFs Assistant. All rights reserved.
            </footer>
        </div>
    );
};

export default App;
